/* ── MODAL ─────────────────────────────────────────────── */
function openModal(id) {
  var p = PRODUCTS[id];
  var lang = currentLang;
  var desc     = lang === 'es' ? p.desc_es     : p.desc_en;
  var badges   = lang === 'es' ? p.badges_es   : p.badges_en;
  var variants = lang === 'es' ? p.variants_es : p.variants_en;
  var phTitle  = lang === 'es' ? 'Encuéntralo en:' : 'Find it at:';
  var varTitle = lang === 'es' ? 'Presentaciones disponibles' : 'Available presentations';

  var badgeHTML = badges.map(function(b) {
    return '<div class="modal-badge">'
      + '<svg viewBox="0 0 15 15" fill="none" style="width:15px;height:15px"><path d="M7.5 2L12 5V10L7.5 13L3 10V5L7.5 2Z" stroke="#1a4f9c" stroke-width="1.3" stroke-linejoin="round"/><path d="M5 7.5L6.8 9.3L10 6" stroke="#1a4f9c" stroke-width="1.3" stroke-linecap="round" stroke-linejoin="round"/></svg>'
      + '<span>' + b + '</span></div>';
  }).join('');

  var varHTML = '';
  if (variants.length > 0) {
    varHTML = '<div class="modal-sec-title">' + varTitle + '</div>'
      + '<div class="modal-variants">'
      + variants.map(function(v) {
          return '<div class="modal-variant">'
            + (v.img ? '<img class="mv-img" src="' + v.img + '" alt="' + v.name + '" onerror="this.style.display=\'none\'">' : '')
            + '<div class="mv-content"><div class="mv-name">' + v.name + '</div>'
            + '<ul class="mv-list">' + v.items.map(function(i) { return '<li>' + i + '</li>'; }).join('') + '</ul>'
            + '</div></div>';
        }).join('')
      + '</div>';
  }

  var phHTML = '<div class="modal-pharmacies">'
    + '<div class="modal-sec-title">' + phTitle + '</div>'
    + '<div class="ph-grid">'
    + PHARMACIES.map(function(ph) {
        return '<a href="' + ph.url + '" target="_blank" class="ph-item">' + ph.name
          + ' <svg viewBox="0 0 11 11" fill="none"><path d="M2 9L9 2M9 2H5.5M9 2V5.5" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round"/></svg></a>';
      }).join('')
    + '</div></div>';

  var posMap = {xicanil:'center center', fungosel:'center center', bronquisedan:'center top', condrox:'center center', oralsone:'center top', milorix:'center 60%'};
  var imgPos = posMap[id] || 'center center';
  document.getElementById('modal-inner').innerHTML =
    '<div class="modal-banner-fallback" style="background:' + p.bg + '">'
    + '<img class="modal-banner" style="object-position:' + imgPos + '" src="' + p.banner + '" alt="' + p.name + '" onerror="this.parentElement.style.height=\'80px\'">'
    + '</div>'
    + '<div class="modal-body">'
    + '<img class="modal-logo" src="' + p.logo + '" alt="' + p.name + '" onerror="this.style.display=\'none\'">'
    + '<p class="modal-tagline">' + desc + '</p>'
    + '<div class="modal-badges">' + badgeHTML + '</div>'
    + varHTML + phHTML
    + '</div>';

  document.getElementById('modal-overlay').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeModal() {
  document.getElementById('modal-overlay').classList.remove('open');
  document.body.style.overflow = '';
}

function closeModalOutside(e) {
  if (e.target === document.getElementById('modal-overlay')) closeModal();
}

document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') closeModal();
});

/* ── LANGUAGE SWITCHER ──────────────────────────────────── */
function toggleLang() {
  currentLang = currentLang === 'es' ? 'en' : 'es';
  document.getElementById('langLabel').textContent = currentLang === 'es' ? 'EN' : 'ES';

  document.querySelectorAll('[data-es]').forEach(function(el) {
    var val = el.getAttribute('data-' + currentLang);
    if (!val) return;
    if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.placeholder = val;
    } else {
      el.innerHTML = val;
    }
  });

  document.querySelectorAll('[data-ph-' + currentLang + ']').forEach(function(el) {
    el.placeholder = el.getAttribute('data-ph-' + currentLang);
  });
}